const BASE_URL = "http://localhost:3001";

export const getFields = async () => {
  const res = await fetch(`${BASE_URL}/fields`);
  if (!res.ok) throw new Error("Không lấy được danh sách sân");
  return res.json();
};

export const getFieldById = async (id) => {
  const res = await fetch(`${BASE_URL}/fields/${id}`);
  if (!res.ok) throw new Error("Không lấy được chi tiết sân");
  return res.json();
};

export const getBookings = async () => {
  const res = await fetch(`${BASE_URL}/bookings`);
  if (!res.ok) throw new Error("Không lấy được danh sách booking");
  return res.json();
};

export const createBooking = async (bookingData) => {
  const res = await fetch(`${BASE_URL}/bookings`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(bookingData),
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.message || "Tạo booking thất bại");
  }

  return res.json();
};

export const getMatches = async () => {
  const res = await fetch(`${BASE_URL}/matches`);
  if (!res.ok) throw new Error("Không lấy được danh sách trận");
  return res.json();
};

export const getMatchPlayers = async (matchId) => {
  const res = await fetch(`${BASE_URL}/match/${matchId}/players`);
  if (!res.ok) throw new Error("Không lấy được danh sách người tham gia");
  return res.json();
};

export const joinMatch = async (joinData) => {
  const res = await fetch(`${BASE_URL}/join`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(joinData),
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.message || "Tham gia trận thất bại");
  }

  return res.json();
};
